def getSuccessors(current,maze):
    succs=[]
    if current.x > 0:
        succs.append(Point(current.x-1,current.y))
    if current.x < len(maze[0])-1:
        succs.append(Point(current.x+1,current.y))
    if current.y > 0:
        succs.append(Point(current.x,current.y-1))
    if current.y < len(maze)-1:
        succs.append(Point(current.x,current.y+1))
    return succs




