from collections import namedtuple, defaultdict

Rect = namedtuple('Rect', ['ID', 'x', 'y', 'w', 'h'])

def parse(lines):
    rectangles = []
    for line in lines:
        ID, rest = line[1:].split(" @ ")
        x,  rest = rest.split(",")
        y,  rest = rest.split(": ")
        w,     h = rest.split("x")
        rectangles.append(Rect(int(ID), int(x), int(y), int(w), int(h)))
    return rectangles


def get_claims(rect):
    claims = []
    for y in range(rect.y, rect.y + rect.h):
        for x in range(rect.x, rect.x + rect.w):
            claims.append((x, y))
    return claims

def overlap(rectangles):
    claim_map = defaultdict(list)

    for rect in rectangles:
        claims = get_claims(rect)
        for x, y in claims:
            claim_map[x, y].append(rect.ID)

    return claim_map, len(list(filter(lambda x: len(x) > 1, claim_map.values())))

