Claim = namedtuple('Claim',['claim_id','offset','size'])
def parse_claim(claim):
    claim_regex = re.compile("#(?P<id>\d+) @ (?P<offset>\d+,\d+): (?P<size>\d+x\d+)")
    claim_match = re.match(claim_regex,claim)
    parsed_claim = Claim(
        claim_id=int(claim_match.group('id')),
        offset=tuple(map(int,claim_match.group('offset').split(','))),
        size=tuple(map(int,claim_match.group('size').split('x')))
    )
    return parsed_claim

ClaimLocation = namedtuple('ClaimLocation',['top_left','top_right','bottom_left','bottom_right'])
def parse_claim_location(parsed_claim):
    return ClaimLocation(
        top_left=parsed_claim.offset,
        top_right=(parsed_claim.offset[0] + parsed_claim.size[0] - 1,parsed_claim.offset[1]),
        bottom_left=(parsed_claim.offset[0],parsed_claim.offset[1] + parsed_claim.size[1] - 1),
        bottom_right=(parsed_claim.offset[0] + parsed_claim.size[0] - 1,parsed_claim.offset[1] + parsed_claim.size[1] - 1)
    )

def claims_overlap(claim1,claim2):
    return not (claim1.bottom_right[1] < claim2.top_left[1] 
                or claim1.top_left[1] > claim2.bottom_right[1] 
                or claim1.bottom_right[0] < claim2.top_left[0] 
                or claim1.top_left[0] > claim2.bottom_right[0]
            )

def part_1(puzzle_input):
    fabric = pd.DataFrame(
        index=pd.RangeIndex(0,1000),
        columns=pd.RangeIndex(0,1000)
    ).fillna(0)

    for claim in puzzle_input:
        parsed_claim = parse_claim(claim)
        fabric.iloc[
            parsed_claim.offset[0]:parsed_claim.offset[0] + parsed_claim.size[0],
            parsed_claim.offset[1]:parsed_claim.offset[1] + parsed_claim.size[1]
        ] += 1

    return (fabric >= 2).sum().sum()

def part_2(puzzle_input):
    puzzle_input =  [parse_claim(claim) for claim in puzzle_input]
    for claim in puzzle_input:
        current_claim_location = parse_claim_location(claim)
        overlaps = [lap for lap in map(lambda x: claims_overlap(current_claim_location,parse_claim_location(x)), puzzle_input) if lap == True]
        if len(overlaps) == 1:
            return claim.claim_id           

