from collections import deque

def same_type(char1: str, char2: str):
    return char1.lower() == char2.lower()


def opposite_polarity(char1: str, char2: str):
    if char1.islower():
        if char2.isupper():
            return True
        else:
            return False
    elif char1.isupper():
        if char2.islower():
            return True
        else:
            return False


def shrink_polymer(polymer_in):
    polymer_out = deque(polymer_in.popleft())
    while polymer_in:
        if same_type(polymer_out[-1], polymer_in[0]) and opposite_polarity(polymer_out[-1],
                                                                       polymer_in[0]):
            polymer_out.pop()
            polymer_in.popleft()
            if not polymer_out:
                polymer_out.append(polymer_in.popleft())
        else:
            polymer_out.append(polymer_in.popleft())
    return len(polymer_out)


def find_shortest_polymer_length(polymer_in):
    letters = set()
    shortest_len = int(float("1e7"))
    for i in polymer_in:
        if i.lower() not in letters:
            letters.add(i.lower())
            test_set = deque([letter for letter in polymer_in if letter.lower() != i.lower()])
            n = shrink_polymer(test_set)
            if n < shortest_len:
                shortest_len = n
    return shortest_len


