from collections import defaultdict

def parse(filename):
    res = []
    with open('year_2018_day_7.txt') as f:
        for line in f:
            line = line.strip()
            splitted = line.split()
            predecessor = splitted[1]
            successor = splitted[-3]
            res.append( (predecessor, successor))
    return res

def create_graph(data):
    graph = defaultdict(list)
    for p, s in data:
        graph[p].append(s)
    return graph

def find_predecessors(graph, node):
    res = []
    for n in graph:
        sucessor = graph[n]
        if node in sucessor:
            res.append(n)
    return res

def find_nodes_with_no_predecessor(graph):
    nodes = []
    for node in graph:
        predecessors = find_predecessors(graph, node)
        if not predecessors:
            nodes.append(node)
    return nodes


def topological_sort(graph):
    S = sorted(find_nodes_with_no_predecessor(graph))
    L = []
    while S:
        n = S[0]
        del S[0]
        L.append(n)
        next_nodes = graph[n]
        del graph[n]
        for m in next_nodes[:]:
            nodes = find_predecessors(graph, m)
            if not nodes:
                S.append(m)
        S = sorted(S)
    return L


def main():
    data = parse('input')
    graph = create_graph(data)
    print(''.join(topological_sort(graph)))

if __name__ == "__main__":
    main()

