input_filename = "../input/input_day8.txt"

class Node:
    def __init__(self, ind, child_remainging, data_len):
        self.ind = ind
        self.child_remaining = child_remainging
        self.data_len = data_len
        self.children = []
        self.data_vals = []

    def __repr__(self):
        return f"Node(ind: {self.ind}, metadata items:{self.data_len}, children:{len(self.children)})"

    def metadata_sum(self):
        return sum(self.data_vals) + sum(child.metadata_sum() for child in self.children)

    @staticmethod
    def value(node):
        if not node.children:
            return sum(node.data_vals)
        return sum(Node.value(node.children[data_val - 1]) for data_val in node.data_vals if data_val < len(node.children) + 1)

def read_file():
    with open('year_2018_day_8.txt') as f:
        return [int(i) for i in f.read().split(' ')]

def setup():
    nums = read_file()
    base = Node(0, nums[0], nums[1])
    total = 0
    ind = 0
    stack = [base]
    while stack:
        top = stack[-1]
        if top.child_remaining == 0:
            stack.pop()
            top.data_vals = nums[(ind + 2):(ind + top.data_len + 2)]
            ind += top.data_len
        else:
            ind += 2
            next = Node(ind, nums[ind], nums[ind + 1])
            stack.append(next)
            top.child_remaining -= 1
            top.children.append(next)
    return base

def part1(tree):
    return tree.metadata_sum()

def part2(tree):
    return Node.value(tree)

def main():
    start_setup = time.time()
    base = setup()
    end_setup = time.time()

    start_part1 = time.time()
    res_part1 = part1(base)
    end_part1 = time.time()

    start_part2= time.time()
    res_part2 = part2(base)
    end_part2 = time.time()

    print(f"part 1: {res_part1}")
    print(f"part 2: {res_part2}")
    print(f"setup took {end_setup - start_setup} seconds")
    print(f"part 1 took {end_part1 - start_part1} seconds")
    print(f"part 2 took {end_part2 - start_part2} seconds")
    print(f"overall took {end_part2 - start_setup} seconds")

if __name__ == '__main__':
    main()

import re
import matplotlib.pyplot as plt

class Point:
    def __init__(self, line):
        test = r'position=<\s*(?P<X>\-?\d+),\s*(?P<Y>\-?\d+)> velocity=<\s*(?P<vx>\-?\d+),\s*(?P<vy>\-?\d+)>\n'
        r = re.match(test, line).groupdict()
        self.x = int(r['X'])
        self.y = int(r['Y'])
        self.vx = int(r['vx'])
        self.vy = int(r['vy'])

    def move(self):
        self.x += self.vx
        self.y += self.vy

    def move_back(self):
        self.x -= self.vx
        self.y -= self.vy


def plot(points):
    points = [(p.x, p.y) for p in points]
    plt.yscale('log')
    plt.scatter(*zip(*points))
    plt.show()


def move_all(points):
    for p in points:
        p.move()

def move_all_back(points):
    for p in points:
        p.move_back()

def bounds(points):
    xmax = max([p.x for p in points])
    ymax = max([p.y for p in points])
    xmin = min([p.x for p in points])
    ymin = min([p.y for p in points])
    return xmax, xmin, ymax, ymin

def box_size(points):
    xmax, xmin, ymax, ymin = bounds(points)
    return (xmax - xmin), (ymax - ymin)


if __name__ == '__main__':
    data = open('year_2018_day_10.txt', 'r').readlines()
    points = [Point(line) for line in data]
    converging = True
    xbound, ybound = box_size(points)
    while converging:
        move_all(points)
        newxbound, newybound = box_size(points)
        if newxbound > xbound and newybound > ybound:
            converging = False
        xbound = newxbound
        ybound = newybound
    move_all_back(points)
    plot(points)

