"""Day 4 of Advent of Code 2020 Solution"""
import re


VALID_FIELDS = {'byr', 'iyr', 'eyr', 'hgt', 'hcl', 'ecl', 'pid'}
License = dict[str, str]


def parse_license_data(file_location) -> list[License]:
    with open('year_2020_day_4.txt', "r") as f:
        data = []
        license = {}
        for line in f:
            current_line = line.strip()
            if current_line:
                for key_val in current_line.strip().split(" "):
                    key, val = key_val.split(":")
                    license[key] = val
            else:
                data.append(license.copy())
                license.clear()
        data.append(license)
    return data


def is_valid_byr(byr: str) -> bool:
    """Validate birth year"""
    return (len(byr) == 4) and (1920 <= int(byr) <= 2002)


def is_valid_iyr(iyr: str) -> bool:
    """Validate issue year"""
    return (len(iyr) == 4) and (2010 <= int(iyr) <= 2020)


def is_valid_eyr(eyr: str) -> bool:
    """Validate expiration year"""
    return (len(eyr) == 4) and (2020 <= int(eyr) <= 2030)


def is_valid_hgt(hgt: str) -> bool:
    """Validate height"""
    height_pattern = r"(\d+)(in|cm)"
    height_validation = {
        'cm': lambda x: 150 <= int(x) <= 193,
        'in': lambda x: 59 <= int(x) <= 76
    }
    if match := re.search(height_pattern, hgt):
        height = match.group(1)
        unit = match.group(2)
        return height_validation[unit](height)
    return False

def is_valid_hcl(hcl: str) -> bool:
    """Validate hair color"""
    return bool(re.match(r"#[0-9a-f]{6}", hcl))


def is_valid_ecl(ecl: str) -> bool:
    """Validate eye color"""
    valid_eye_colors = {'amb', 'blu', 'brn', 'gry', 'grn', 'hzl', 'oth'}
    return ecl in valid_eye_colors


def is_valid_pid(pid: str) -> bool:
    """Validate passport ID"""
    return bool(re.match(r"\b[0-9]{9}\b", pid))


def has_required_fields(license: License) -> bool:
    """License contains all required fields"""
    return VALID_FIELDS.issubset(set(license.keys()))


def all_license_fields_valid(license: License) -> bool:
    validator = {'byr': is_valid_byr,
                 'iyr': is_valid_iyr,
                 'eyr': is_valid_eyr,
                 'hgt': is_valid_hgt,
                 'hcl': is_valid_hcl,
                 'ecl': is_valid_ecl,
                 'pid': is_valid_pid,
                  }
    return all([validator[k](license[k]) for k in validator])


def is_valid_license(license: License) -> bool:
    if has_required_fields(license) and all_license_fields_valid(license):
        return True
    return False


def part_a(file_location):
    data = parse_license_data(file_location)
    n_valid = 0
    for license in data:
        if has_required_fields(license):
            n_valid += 1
        else:
            continue
    return n_valid


def part_b(file_location):
    data = parse_license_data(file_location)
    n_valid = 0
    for license in data:
        if is_valid_license(license):
            n_valid += 1
        else:
            continue
    return n_valid


if __name__ == '__main__':
    print(part_a(r"data\day4.txt"))
