from __future__ import annotations

from dataclasses import dataclass
import re
from typing import Any, Dict, Optional, Tuple


@dataclass
class PassportField:
    value: Optional[Any]

    def validate(self) -> bool:
        raise NotImplementedError


@dataclass
class BirthYear(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                return 1920 <= int(self.value) <= 2002
            except ValueError:
                return False

        return False


@dataclass
class IssueYear(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                return 2010 <= int(self.value) <= 2020
            except ValueError:
                return False

        return False


@dataclass
class ExpirationYear(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                return 2010 <= int(self.value) <= 2030
            except ValueError:
                return False

        return False


@dataclass
class Height(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                height = int(self.value[:-2])
                return (
                    ((150 <= height <= 193) and "cm" in self.value) or
                    ((59 <= height <= 76) and "in" in self.value)
                )
            except ValueError:
                return False

        return False


@dataclass
class HairColor(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            return re.match(r"\#[0-9a-f]{6}", self.value) is not None

        return False


@dataclass
class EyeColor(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            return any(
                color == self.value for color in ["amb", "blu", "brn", "gry", "grn", "hzl", "oth"]
            )

        return False


@dataclass
class PassportID(PassportField):
    def validate(self) -> bool:
        if self.value is not None:
            try:
                int(self.value)
                return len(self.value) == 9
            except ValueError:
                return False

        return False


@dataclass
class CountryID(PassportField):
    def validate(self) -> bool:
        return True


@dataclass
class Passport:
    birth_year: BirthYear
    issue_year: IssueYear
    expiration_year: ExpirationYear
    height: Height
    hair_color: HairColor
    eye_color: EyeColor
    passport_id: PassportID
    country_id: CountryID

    def check_validity_v1(self) -> bool:
        for field in self.__dict__.values():
            if field.value is None and not isinstance(field, CountryID):
                return False

        return True

    def check_validity_v2(self) -> bool:
        for field in self.__dict__.values():
            if not field.validate():
                return False

        return True

    @classmethod
    def deserialize_from_input(cls, input_entry: Dict[str, str]) -> Passport:
        return cls(
            birth_year=BirthYear(input_entry.get("byr")),
            issue_year=IssueYear(input_entry.get("iyr")),
            expiration_year=ExpirationYear(input_entry.get("eyr")),
            height=Height(input_entry.get("hgt")),
            hair_color=HairColor(input_entry.get("hcl")),
            eye_color=EyeColor(input_entry.get("ecl")),
            passport_id=PassportID(input_entry.get("pid")),
            country_id=CountryID(input_entry.get("cid")),
        )


def main() -> Tuple[int, int]:
    with open('year_2020_day_4.txt', "r") as f:
        passport_entries_raw = [passport_entry.strip() for passport_entry in f.read().split("\n\n")]
        passport_entries_massaged = [
            [field.split(":") for field in passport_entry.split()] for
            passport_entry in passport_entries_raw
        ]

        passport_entries = [
            Passport.deserialize_from_input({field[0]: field[1] for field in passport_entry}) for
            passport_entry in passport_entries_massaged
        ]

        return (
            sum(passport_entry.check_validity_v1() for passport_entry in passport_entries),
            sum(passport_entry.check_validity_v2() for passport_entry in passport_entries)
        )


if __name__ == "__main__":
    print(main())

