"""Day 5 of Advent of Code 2020 Solution"""

from math import ceil


def bin_search(bp: str, length: int) -> int:
    """Perform front/back and left/right binary search on seat string"""
    low, high = 0, length - 1
    for direction in bp:
        if direction == "F" or direction == "L":
            high = low + (high - low) // 2
        else:
            low = low + ceil((high - low) / 2)
    return (high + low) // 2


def find_seat(bp: str) -> tuple[int, int]:
    """Get the row and column for a seat based on the boarding pass string"""
    row = bin_search(bp[:-3], 128)
    col = bin_search(bp[-3:], 8)
    return row, col


def find_seat_id(bp: str) -> int:
    """Get the seat ID based on the boarding pass string"""
    row, col = find_seat(bp)
    return (row * 8) + col


