import math
def recRowCol(colArr, ncolrow, col):
    if len(colArr) != 0:
        curR = colArr.pop(0)
        if curR == 'L' or curR =="F":
            ncolrow = math.ceil(min(ncolrow)), math.floor(sum(ncolrow)/2)
        else:
            ncolrow = math.ceil(sum(ncolrow)/2), math.floor(max(ncolrow))
        return recRowCol(colArr, ncolrow,col)
    else:
        if col is True:
            return max(ncolrow)
        else:
            return min(ncolrow)

