import collections
import timeit

class BinaryBoarding:

    def __init__(self, rows, cols):
        self.seats = []
        with open('year_2020_day_5.txt') as f:
            for boarding_pass in f:
                seat = self.process_pass(boarding_pass.rstrip())
                self.seats.append(seat)
        self.rows = rows
        self.cols = cols

    @staticmethod
    def _partition(seat_str, lower_letter, upper_letter, position_range):
        next_letter, next_str = seat_str[:1], seat_str[1:]
        assert next_letter in (lower_letter, upper_letter)
        start, end = position_range
        middle_lower_bound = start + ((end - start) // 2)
        middle_upper_bound = middle_lower_bound + 1
        if next_letter == lower_letter:
            next_range = (start, middle_lower_bound)
        elif next_letter == upper_letter:
            next_range = (middle_upper_bound, end)
        else:
            raise Exception('unexpected')
        if not next_str:
            assert next_range[0] == next_range[1]
            return next_range[0]
        else:
            return BinaryBoarding._partition(next_str, lower_letter, upper_letter, next_range)

    @staticmethod
    def _process_pass(seat_str, lower_letter, upper_letter):
        position_range = (0, (2 ** len(seat_str)) - 1)
        return BinaryBoarding._partition(seat_str, lower_letter, upper_letter, position_range)

    @staticmethod
    def process_pass(boarding_pass):
        row_str, col_str = boarding_pass[:7], boarding_pass[7:]
        row = BinaryBoarding._process_pass(row_str, lower_letter='F', upper_letter='B')
        col = BinaryBoarding._process_pass(col_str, lower_letter='L', upper_letter='R')
        return row, col

    @staticmethod
    def get_seat_id(seat):
        row, col = seat
        return row * 8 + col

    def highest_seat_id(self):
        highest_seat_id = 0
        for seat in self.seats:
            seat_id = self.get_seat_id(seat)
            if seat_id > highest_seat_id:
                highest_seat_id = seat_id
        return highest_seat_id

    def find_my_seat(self):
        seats_by_row = collections.defaultdict(list)
        for seat_row, seat_col in self.seats:
            seats_by_row[seat_row].append(seat_col)
        incomplete_rows = {row: cols for row, cols in seats_by_row.items() if len(cols) != self.cols}
        very_front = min(incomplete_rows)
        very_back = max(incomplete_rows)
        my_row = {row: cols for row, cols in incomplete_rows.items() if row not in (very_front, very_back)}
        my_seat_row, = list(my_row.keys())
        potential_seat_cols, = list(my_row.values())
        my_seat_col, = set(range(self.cols)) - set(potential_seat_cols)
        return my_seat_row, my_seat_col


def main():
    binary_boarding = BinaryBoarding(rows=120, cols=8)
    print(f'Highest seat id = {binary_boarding.highest_seat_id()}')
    print(f'My seat id = {binary_boarding.get_seat_id(binary_boarding.find_my_seat())}')


