def count_contents(data, colour):
    if colour == 'other':
        return 0
    count = 0
    for cont in data[colour]:
        num_str = cont.split()[0]
        if num_str == 'no':
            num = 0
        else:
            num = int(num_str)
        col = cont.split(maxsplit=1)[1]
        count = count + num * (count_contents(data, col) + 1)
    return count


