from functools import cache


@cache
def get_bag_data(file_location: str) -> dict[str, dict[str, int]]:
    """{'muted white bag': {'dark orange bag': 4, 'bright white bag': 3}}"""
    bags = {}
    with open('year_2020_day_7.txt', "r") as f:
        for line in f.readlines():
            line = line.strip().split(" contain ")
            outer_bag_str = line[0]
            if outer_bag_str[-1] == "s":
                outer_bag = outer_bag_str[:-1]
            else:
                outer_bag = outer_bag_str

            inner_bags = {}
            if line[1] != "no other bags.":
                for inner_bag in line[1][:-1].split(", "):
                    bag_count = int(inner_bag[0])
                    bag_name = inner_bag[2:] if bag_count == 1 else inner_bag[2:-1]
                    inner_bags[bag_name] = bag_count

            bags[outer_bag] = inner_bags
    return bags


def part_a(file_location: str) -> int:
    bags = get_bag_data(file_location)
    n_contains_shiny_gold = []

    @cache
    def bag_search(bag_type: str) -> bool:
        if "shiny gold bag" in bags[bag_type]:
            n_contains_shiny_gold.append(1)
            return True
        for bag in bags[bag_type]:
            if bag_search(bag):
                n_contains_shiny_gold.append(1)
                return True
        return False

    for bag in bags:
        bag_search(bag)

    return sum(n_contains_shiny_gold)



def part_b(file_location):
    bags = get_bag_data(file_location)

    @cache
    def count_bags(bag_to_count):
        n_inner_bags = 0
        for bag in bags[bag_to_count]:
            n_inner_bags += (
                bags[bag_to_count][bag] + count_bags(bag) * bags[bag_to_count][bag]
            )
        return n_inner_bags

    return count_bags("shiny gold bag")


