from collections import Counter
from functools import partial
from itertools import dropwhile
from more_itertools import iterate

def resolve_byte(key, bss, idx):
    return max(Counter(bs[idx] for bs in bss).items(), key=key)[0]

def resolve_greek(bss, key):
    return int("".join(
        resolve_byte(key, bss, idx) for idx in range(len(bss[0]))), 2)

def resolve_gamma(bss):
    return resolve_greek(bss, lambda tup: tup[1])

def resolve_epsilon(bss):
    return resolve_greek(bss, lambda tup: -tup[1])

def part_1(filename):
    with open('year_2021_day_3.txt') as f:
        lines = [line.strip() for line in f]
        gamma, epsilon = resolve_gamma(lines), resolve_epsilon(lines)
        return gamma * epsilon

def next_filter(key, bss, idx):
    bit = resolve_byte(key, bss, idx)
    return [bs for bs in bss if bs[idx] == bit], idx + 1

def uncurry(f):
    return lambda tup: f(*tup)

def get_rating(bss, key):
    return next(dropwhile(lambda tup: len(tup[0]) > 1,
        iterate(uncurry(partial(next_filter, key)), (bss, 0))))

def get_oxygen(bss):
    return int(get_rating(bss, lambda tup: (tup[1], tup[0]))[0][0], 2)

def get_co2(bss):
    return int(get_rating(bss, lambda tup: (-tup[1], -ord(tup[0])))[0][0], 2)

def part_2(filename):
    with open('year_2021_day_3.txt') as f:
        lines = [line.strip() for line in f]
        oxygen, co2 = get_oxygen(lines), get_co2(lines)
