def myrange(x1, y1, x2, y2):
    while True:
        yield(x1, y1)
        if x1 == x2 and y1 == y2:
            return
        if x1 != x2:
            x1 += (1 if x1 <= x2 else -1)
        if y1 != y2:
            y1 += (1 if y1 <= y2 else -1)


