def calcFuelCosts(constantRate):
    crabs = [int(i) for i in open('year_2021_day_7.txt','r').readlines()[0].split(',')]
    minFuel, position = None, None
    for t in range(min(crabs),max(crabs)+1):
        fuel = 0
        for c in crabs:
            distance = abs(t-c)
            if constantRate:
                fuel += distance
            else:
                fuel += int(distance*(distance+1)/2)
        if (not minFuel or fuel < minFuel):
            minFuel, position = fuel, t
    print(f'Fuel:{minFuel}, Position:{position}')

