        return [i for i in [(r-1,c),(r+1,c),(r,c-1),(r,c+1)] \
            if i[0] >= 0 and i[0] <= last['r'] and i[1] >= 0 and i[1] <= last['c']]


    def getbs(r: int, c:int, hist: set) -> set:
        ns = getns(r, c)

        hist.add((r, c))

        for i in ns:
