def main(fp):
    data = list(parse(fp))

    m = len(data)
    n = len(data[0])

    def adjacent(i, j):
        p = [(0,1), (1,0), (0,-1), (-1,0)]
        for di, dj in p:
            if 0 <= i+di < m and 0 <= j+dj < n:
                yield i+di, j+dj

    mins = []
    for i, j in product(range(m), range(n)):
        if all(data[i][j] < data[i2][j2] for i2, j2 in adjacent(i, j)):
            mins.append((i, j))

    return sum(1+data[i][j] for i, j in mins)


