# Returns 0 if draw, -1 if opponent wins, and 1 if I win.
def find_winner(opponent, me):
    if opponent == me:
        return 0

    if opponent == 'R':
        return 1 if me == 'P' else -1

    if opponent == 'P':
        return 1 if me == 'S' else -1

    return 1 if me == 'R' else -1


