def solve_part_1(adj, files_in_dir):
    res = 0

    def search(root):
        curr_total = 0
        for nei in adj[root]:
            curr_total += search(nei)

        for size, _ in files_in_dir[root]:
            curr_total += size

        if curr_total <= 100000:
            nonlocal res
            res += curr_total

        return curr_total

    search('')
    return res


def solve_part_2(adj, files_in_dir):
    lookup = {}

    def search(root):
        curr_total = 0
        for nei in adj[root]:
            curr_total += search(nei)

        for size, _ in files_in_dir[root]:
            curr_total += size

        lookup[root] = curr_total
        return curr_total

    search('')
    target = 30000000 - (70000000 - lookup[''])
    return min(value for value in lookup.values() if value >= target)


