def search(time, distance, low, high, low_high):
    while low < high:
        mid = (low + high) // 2
        if (time - mid) * mid > distance:
            low = mid + 1 if low_high else low
            high = high if low_high else mid
        else:
            low = low if low_high else mid + 1
            high = mid if low_high else high
    return low - low_high

