def category(hand):
    c = Counter(hand)
    freqs = [x[1] for x in c.most_common()]
    if freqs == [5]:
        return 1  # five of a kind
    elif freqs == [4,1]:
        return 2  # four of a kind
    elif freqs == [3,2]:
        return 3  # full house
    elif freqs == [3,1,1]:
        return 4  # three of a kind
    elif freqs == [2,2,1]:
        return 5  # two pair
    elif freqs == [2,1,1,1]:
        return 6  # one pair
    else:
        return 7  # high card


