def match(s, p, i, j):
    map = {}
    def check(i, j, s, p):
        if (i, j, p) in map:
            return map[(i, j, p)]
        if i == len(s) and j == len(p):
            return 1
        elif j == len(p):
            return 0
        elif i == len(s):
            if p[j] == '*':
                return check(i, j + 1, s, p)
            return 0
        else:
            res = 0
            if (s[i] == '#' or s[i] == '?') and p[j] == '#':
                res += check(i + 1, j + 1, s, p)
            elif (s[i] == '?' or s[i] == '.') and p[j] == '*':
                res += check(i + 1, j, s, p)
                res += check(i, j + 1, s, p)
            elif s[i] == '#' and p[j] == '*':
                res += check(i, j + 1, s, p)
            elif (s[i] == '?' or s[i] == '.') and p[j] == '+':
                res += check(i + 1, j, s, p[:j] + '*' + p[j + 1:])
        map[(i, j, p)] = res
        return res

    return check(i, j, s, p)    

