import os
from collections import Counter

PATH_TO_FILE = f"{os.path.dirname(os.path.realpath(__file__))}/data.in"

def parse_input():
  with open('year_2024_day_11.txt', "r") as f:
    return [int(x) for x in f.read().strip().split(" ")]

def blink(stones: Counter[int]) -> Counter[int]:
    new_state: Counter[int] = Counter()
    for stone, count in stones.items():
        if stone == 0:
            new_state[1] += count
        elif len(as_str := str(stone)) % 2 == 0:
            left, right = int(as_str[: len(as_str) // 2]), int(as_str[len(as_str) // 2 :])
            new_state[left] += count
            new_state[right] += count
        else:
            new_state[stone * 2024] += count
    return new_state

def part1():
    stones = Counter(parse_input())
    for _ in range(25):
        stones = blink(stones)
    return sum(stones.values())

import re
import numpy as np
from scipy import optimize

parts = np.zeros(2, dtype=int)
with open('year_2024_day_13.txt') as file:
    for line in file:
        if "Button" in line:
            match = re.search(r"(.): X\+(\d+), Y\+(\d+)", line)
            if match.group(1) == "A":
                a = np.array([[match.group(2), 0], [match.group(3), 0]], dtype=int)
            else:
                a[:, 1] = [match.group(2), match.group(3)]
        elif "Prize" in line:
            match = re.search(r"X=(\d+), Y=(\d+)", line)
            b = np.array([match.group(1), match.group(2)], dtype=int)
            a = np.vstack((a, -a))
            for i in range(2):
                b += int(1e13) * i
                b2 = np.hstack((b, -b))
                ret = optimize.linprog(
                    np.array([-1, -1]), A_ub=a, b_ub=b2, integrality=[True, True]
                )
                if ret.success:
                    parts[i] += ret.x @ [3, 1]

print(f"{parts[0]} {parts[1]}")

